sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Catalog Capability Map CRUD operations
    // Create
    var gr = new GlideRecord('u_catalog_capability_map');
    gr.initialize();
    gr.u_capability = 'AI Orchestration';
    gr.u_catalog_item = 'Test Catalog Item';
    var id = gr.insert();
    assert.isTrue(id, 'Catalog capability map should be created');

    // Read
    gr = new GlideRecord('u_catalog_capability_map');
    gr.get(id);
    assert.isTrue(gr.isValid(), 'Catalog capability map should exist');

    // Update
    gr.u_catalog_item = 'Updated Catalog Item';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_catalog_capability_map');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Catalog capability map should be deleted');
})(step, $library);
